import React, { useState, useEffect } from "react";
import { Link } from "react-router-dom";
import { motion, AnimatePresence } from "framer-motion";
import { Menu, X, Instagram, Facebook } from "lucide-react";
import logo from "../assets/images/logo.png";

const Navbar = () => {
  const [isOpen, setIsOpen] = useState(false);
  const [isScrolled, setIsScrolled] = useState(false);

  useEffect(() => {
    const handleScroll = () => {
      setIsScrolled(window.scrollY > 50);
    };
    window.addEventListener("scroll", handleScroll);
    return () => window.removeEventListener("scroll", handleScroll);
  }, []);

  const menuItems = [
    { title: "Home", path: "/" },
    { title: "Academy", path: "/academy" },
    { title: "Pro Services", path: "/pro-services" },
    { title: "Our Story", path: "/story" },
    { title: "Connect", path: "/connect" },
  ];

  return (
    <nav
      className={`fixed w-full z-50 transition-all duration-500 ${
        isScrolled
          ? "bg-charcoal/90 backdrop-blur-lg border-b border-gold/30 shadow-elegant"
          : "bg-charcoal/40 backdrop-blur-md border-b border-gold/10"
      }`}
    >
      <div className="max-w-7xl mx-auto px-6 lg:px-12">
        <div className="flex justify-between items-center h-20">
          {/* Logo */}
          <Link to="/" className="flex items-center group">
            <img
              src={logo}
              alt="Dream of Dance Studio Logo"
              className="h-12 w-auto transition-transform group-hover:scale-105"
            />
          </Link>

          {/* Desktop Menu */}
          <div className="hidden md:flex space-x-12">
            {menuItems.map((item) => (
              <Link
                key={item.path}
                to={item.path}
                className="text-xs font-montserrat uppercase tracking-widest text-ivory/70 hover:text-gold transition-colors duration-300 relative group"
              >
                {item.title}
                <span className="absolute bottom-0 left-0 w-0 h-0.5 bg-gradient-gold group-hover:w-full transition-all duration-300" />
              </Link>
            ))}
          </div>

          {/* Desktop Social Icons */}
          <div className="hidden md:flex items-center space-x-6">
            <a
              href="#"
              className="text-gold/60 hover:text-gold transition-colors duration-300 hover:scale-110"
            >
              <Instagram size={18} strokeWidth={1.5} />
            </a>
            <a
              href="#"
              className="text-gold/60 hover:text-gold transition-colors duration-300 hover:scale-110"
            >
              <Facebook size={18} strokeWidth={1.5} />
            </a>
          </div>

          {/* Mobile Toggle */}
          <button
            className="md:hidden text-gold hover:text-ivory transition-colors"
            onClick={() => setIsOpen(!isOpen)}
            aria-label="Toggle menu"
          >
            {isOpen ? (
              <X size={28} strokeWidth={1.5} />
            ) : (
              <Menu size={28} strokeWidth={1.5} />
            )}
          </button>
        </div>
      </div>

      {/* Mobile Drawer */}
      <AnimatePresence>
        {isOpen && (
          <motion.div
            initial={{ opacity: 0, x: "100%" }}
            animate={{ opacity: 1, x: 0 }}
            exit={{ opacity: 0, x: "100%" }}
            transition={{ type: "spring", damping: 20, stiffness: 300 }}
            className="fixed inset-0 top-20 bg-charcoal/95 backdrop-blur-xl z-40 flex flex-col items-center justify-start space-y-8 pt-12"
          >
            <div className="flex flex-col space-y-8 w-full items-center">
              {menuItems.map((item, index) => (
                <motion.div
                  key={item.path}
                  initial={{ opacity: 0, y: 20 }}
                  animate={{ opacity: 1, y: 0 }}
                  transition={{ delay: index * 0.1 }}
                >
                  <Link
                    to={item.path}
                    onClick={() => setIsOpen(false)}
                    className="text-xl font-cinzel tracking-widest text-ivory hover:text-gold transition-colors duration-300"
                  >
                    {item.title}
                  </Link>
                </motion.div>
              ))}
            </div>

            {/* Mobile Social Icons */}
            <motion.div
              initial={{ opacity: 0, y: 20 }}
              animate={{ opacity: 1, y: 0 }}
              transition={{ delay: 0.5 }}
              className="flex space-x-8 pt-8 border-t border-gold/20"
            >
              <a
                href="#"
                className="text-gold/60 hover:text-gold transition-colors"
              >
                <Instagram size={24} />
              </a>
              <a
                href="#"
                className="text-gold/60 hover:text-gold transition-colors"
              >
                <Facebook size={24} />
              </a>
            </motion.div>
          </motion.div>
        )}
      </AnimatePresence>
    </nav>
  );
};

export default Navbar;
